import React, { useEffect, useState } from 'react';
import ResumeService from '../services/ResumeService';

import jsPDF from "jspdf";
import html2canvas from "html2canvas";

function AllResumes() {

  const [resumes, setResumes] = useState([]);
  const [editingId, setEditingId] = useState(null);
  const [editedResume, setEditedResume] = useState({});

  // ================= LOAD =================
  useEffect(() => {
    fetchResumes();
  }, []);

  const fetchResumes = async () => {
    try {
      const response = await ResumeService.getAllResumes();
      setResumes(response.data);
    } catch (error) {
      console.log(error);
      alert("Backend Not Running or Token Missing");
    }
  };

  // ================= DELETE =================
  const deleteResume = async (id) => {
    try {
      await ResumeService.deleteResume(id);
      alert("Deleted Successfully");
      fetchResumes();
    } catch (error) {
      console.log(error);
      alert("Delete Failed");
    }
  };

  // ================= EDIT =================
  const startEdit = (resume) => {
    setEditingId(resume.id);
    setEditedResume(resume);
  };

  const handleChange = (e) => {
    setEditedResume({
      ...editedResume,
      [e.target.name]: e.target.value
    });
  };

  const updateResume = async () => {
    try {
      await ResumeService.updateResume(editingId, editedResume);
      alert("Updated Successfully");
      setEditingId(null);
      fetchResumes();
    } catch (error) {
      console.log(error);
      alert("Update Failed");
    }
  };

  // ================= DOWNLOAD PDF =================
  const downloadPDF = async (resume) => {

    const input = document.getElementById(`resume-${resume.id}`);

    if (!input) {
      alert("Resume not found");
      return;
    }

    html2canvas(input, {
      scale: 2,
      useCORS: true
    }).then((canvas) => {

      const imgData = canvas.toDataURL("image/png");

      const pdf = new jsPDF("p", "mm", "a4");

      const pdfWidth = pdf.internal.pageSize.getWidth();
      const imgWidth = pdfWidth;
      const imgHeight = (canvas.height * pdfWidth) / canvas.width;

      pdf.addImage(imgData, "PNG", 0, 0, imgWidth, imgHeight);

      pdf.save(`${resume.fullName}_resume.pdf`);
    });
  };

  return (

    <div className="container mt-5 mb-5">

      <h1 className="mb-4">All Resumes</h1>

      {resumes.length === 0 ? (
        <h4>No Resume Found</h4>
      ) : (

        resumes.map((resume) => (

          <div
            className="card shadow p-4 mb-4"
            key={resume.id}
            id={`resume-${resume.id}`}
          >

            {editingId === resume.id ? (

              // ================= EDIT MODE =================
              <div>

                <input
                  name="fullName"
                  value={editedResume.fullName || ""}
                  className="form-control mb-2"
                  onChange={handleChange}
                />

                <input
                  name="email"
                  value={editedResume.email || ""}
                  className="form-control mb-2"
                  onChange={handleChange}
                />

                <input
                  name="phone"
                  value={editedResume.phone || ""}
                  className="form-control mb-2"
                  onChange={handleChange}
                />

                <textarea
                  name="summary"
                  value={editedResume.summary || ""}
                  className="form-control mb-2"
                  rows="3"
                  onChange={handleChange}
                />

                <input
                  name="skills"
                  value={editedResume.skills || ""}
                  className="form-control mb-3"
                  onChange={handleChange}
                />

                <button className="btn btn-success me-2" onClick={updateResume}>
                  Save
                </button>

                <button className="btn btn-secondary" onClick={() => setEditingId(null)}>
                  Cancel
                </button>

              </div>

            ) : (

              // ================= VIEW MODE =================
              <div className="row">

                <div className="col-md-3">
                  {resume.profileImage && (
                    <img
                      src={resume.profileImage}
                      alt="Profile"
                      className="img-fluid rounded-circle"
                      style={{
                        width: "150px",
                        height: "150px",
                        objectFit: "cover"
                      }}
                    />
                  )}
                </div>

                <div className="col-md-9">

                  <h3>{resume.fullName}</h3>

                  <p><b>Email:</b> {resume.email}</p>
                  <p><b>Phone:</b> {resume.phone}</p>
                  <p><b>Skills:</b> {resume.skills}</p>
                  <p><b>Summary:</b> {resume.summary}</p>

                  <button
                    className="btn btn-primary me-2"
                    onClick={() => startEdit(resume)}
                  >
                    Edit
                  </button>

                  <button
                    className="btn btn-danger me-2"
                    onClick={() => deleteResume(resume.id)}
                  >
                    Delete
                  </button>

                  <button
                    className="btn btn-success"
                    onClick={() => downloadPDF(resume)}
                  >
                    Download PDF
                  </button>

                </div>

              </div>

            )}

          </div>

        ))

      )}

    </div>
  );
}

export default AllResumes;
